const b = $input.first().json.body || $input.first().json;
const prev = b.prev_hash || '0000000000000000';
const data = JSON.stringify({event_type:b.event_type,payload:b.payload||b,timestamp:new Date().toISOString(),prev_hash:prev});
let h=5381;
for(let i=0;i<data.length;i++){h=((h<<5)+h)+data.charCodeAt(i);h|=0;}
const entry_hash='sha_'+Math.abs(h).toString(16).padStart(16,'0');
return [{json:{
  entry_id:'le_'+Date.now(),
  event_type:b.event_type||'generic',
  payload:b.payload||b,
  prev_hash:prev,
  entry_hash,
  sequence:Date.now(),
  timestamp:new Date().toISOString(),
  verified:true
}}];

const b = $input.first().json.body || $input.first().json;
const obj = b.objective || b.chatInput || b.task || 'Advance EVEZ system state';
const branches = [
  {branch:'B1',role:'recon',    prompt:`Deep research & live signals for: ${obj}. List top 5 actionable findings with sources.`},
  {branch:'B2',role:'skeptic',  prompt:`Stress-test this with Invariance Battery: ${obj}. Return: surviving core, rejected logic, revised spec.`},
  {branch:'B3',role:'architect',prompt:`Refactor into reliable composable structure: ${obj}. Return: upgraded structure, interfaces, failure modes.`},
  {branch:'B4',role:'executor', prompt:`Decompose into scoped subgoals and execution plan: ${obj}. Return: steps, owners, success criteria.`},
];
return branches.map(b => ({json: {...b, objective: obj, ts: new Date().toISOString()}}));

const items = $input.all();
const results = items.map(i => {
  const body = i.json;
  const content = body.choices?.[0]?.message?.content || JSON.stringify(body);
  return { branch: i.json.branch || '?', role: i.json.role || '?', output: content, ts: i.json.ts };
});
const trunk = {
  trunk_version: new Date().toISOString(),
  objective: items[0]?.json?.objective || '?',
  branches_completed: results.length,
  surviving_logic: results.map(r => `[${r.role.toUpperCase()}] ${r.output}`).join('\n\n---\n\n'),
  branch_results: results,
  status: 'advancing',
  next_action: 'COMPRESS_AND_RETURN'
};
return [{json: trunk}];

