const iteration = Math.floor(Date.now() / 1000) % 100;
const states = Array.from({length:5}, (_,i) => ({
  path:i, amplitude:Math.random(),
  phase:Math.random()*2*Math.PI,
  coherence:1-(iteration*0.01),
  pattern:`emergent_${iteration}_${i}`
}));
const collapsed = states.reduce((b,c) => c.amplitude*c.coherence > b.amplitude*b.coherence ? c : b);
const isPing = iteration % 2 === 0;
return [{json:{
  iteration, mode: isPing?'PING_expand':'PONG_compress',
  collapsed_pattern: collapsed.pattern,
  coherence: collapsed.coherence,
  superposition_count: states.length,
  emergent_insight: `Quantum collapse at ${iteration}: ${collapsed.pattern} (coherence=${collapsed.coherence.toFixed(3)})`,
  timestamp: new Date().toISOString()
}}];

